import React, { useState, useEffect } from 'react';
import axios from 'axios';

function FormPaciente({ onNovoPaciente, pacienteEditando, onFimEdicao }) {
  // estados principais
  const [numeroProntuario, setNumeroProntuario] = useState('');
  const [nome, setNome] = useState('');
  const [telefone, setTelefone] = useState('');
  const [mensagem, setMensagem] = useState('');

  // novos campos não obrigatórios
  const [formData, setFormData] = useState({
    numero_prontuario: '',
    numero_gaveta: '',
    rg: '',
    cpf: '',
    data_nascimento: '',
    idade: '',
    cidade: '',
    endereco: '',
    numero: '',
    observacao: ''
  });

  // preenche o formulário ao editar
  useEffect(() => {
    if (pacienteEditando) {
      setNumeroProntuario(pacienteEditando.numero_prontuario || '');
      setNome(pacienteEditando.nome || '');
      setTelefone(formatarTelefone(pacienteEditando.telefone || ''));
      setFormData({
        numero_prontuario: pacienteEditando.numero_prontuario || '',
        numero_gaveta:     pacienteEditando.numero_gaveta    || '',
        rg:                pacienteEditando.rg               || '',
        cpf:               pacienteEditando.cpf              || '',
        data_nascimento:   pacienteEditando.data_nascimento  || '',
        idade:             pacienteEditando.idade            || '',
        cidade:            pacienteEditando.cidade           || '',
        endereco:          pacienteEditando.endereco         || '',
        numero:            pacienteEditando.numero           || '',
        observacao:        pacienteEditando.observacao       || ''
      });
    } else {
      setNumeroProntuario('');
      setNome('');
      setTelefone('');
      setFormData({
        numero_prontuario: '', numero_gaveta: '', rg: '', cpf: '', data_nascimento: '',
        idade: '', cidade: '', endereco: '', numero: '', observacao: ''
      });
    }
    setMensagem('');
  }, [pacienteEditando]);

  function validarNomeCompleto(valor) {
    const partes = valor.trim().split(/\s+/);
    return partes.length >= 2 && partes.every(p => p.length >= 2 && /^[A-Za-zÀ-ÖØ-öø-ÿ]+$/.test(p));
  }

  function formatarTelefone(campo) {
    const digitos = campo.replace(/\D/g, '');
    if (digitos.length <= 2) return digitos.replace(/^(\d{0,2})/, '($1');
    if (digitos.length <= 6) return digitos.replace(/^(\d{2})(\d{0,4})/, '($1) $2');
    return digitos.replace(/^(\d{2})(\d{5})(\d{0,4}).*/, '($1) $2-$3');
  }

  const handleNomeChange = e => setNome(e.target.value);
  const handleTelefoneChange = e => setTelefone(formatarTelefone(e.target.value));
  const handleNumeroChange = e => setNumeroProntuario(e.target.value);

  const handleSubmit = async e => {
    e.preventDefault();
    setMensagem('');

    if (!validarNomeCompleto(nome)) {
      setMensagem('Informe nome e sobrenome, cada um com ao menos 2 letras.');
      return;
    }

    const somenteDigitos = telefone.replace(/\D/g, '');
    if (!(somenteDigitos.length === 10 || somenteDigitos.length === 11)) {
      setMensagem('Telefone inválido. Use 10 ou 11 dígitos.');
      return;
    }

    // monta o objeto com todos os campos
    const dados = {
      numero_prontuario: numeroProntuario.trim() || null,
      nome: nome.trim(),
      telefone: somenteDigitos,
      numero_gaveta:   formData.numero_gaveta || null,
      rg:              formData.rg            || null,
      cpf:             formData.cpf           || null,
      data_nascimento: formData.data_nascimento || null,
      idade:           formData.idade         || null,
      cidade:          formData.cidade        || null,
      endereco:        formData.endereco      || null,
      numero:          formData.numero        || null,
      observacao:      formData.observacao    || null
    };

    try {
      if (pacienteEditando) {
        await axios.put(`/api/pacientes/${pacienteEditando.id}`, dados);
        setMensagem('Paciente atualizado com sucesso!');
        onNovoPaciente();
      } else {
        await axios.post('/api/pacientes', dados);
        setMensagem('Paciente cadastrado com sucesso!');
        onNovoPaciente();
        setNome(''); setTelefone(''); setNumeroProntuario('');
        setFormData({
          numero_prontuario: '', numero_gaveta: '', rg: '', cpf: '', data_nascimento: '',
          idade: '', cidade: '', endereco: '', numero: '', observacao: ''
        });
      }
    } catch {
      setMensagem(pacienteEditando
        ? 'Erro ao atualizar paciente.'
        : 'Erro ao cadastrar paciente.'
      );
    }
  };

  return (
    <div className="bg-white mx-auto max-w-lg rounded-2xl p-6">
      <form onSubmit={handleSubmit} autoComplete="off">
        <h2 className="text-2xl font-bold mb-6 text-gray-800">
          {pacienteEditando ? 'Editar Paciente' : 'Novo Paciente'}
        </h2>

        {/* Nº Prontuário */}
        <div className="mb-6 max-w-xs">
          <label htmlFor="numero_prontuario" className="block mb-2 font-medium text-gray-700">
            Número do Prontuário <small>(opcional)</small>
          </label>
          <input
            id="numero_prontuario"
            type="text" maxLength={8}
            value={numeroProntuario}
            onChange={handleNumeroChange}
            placeholder="Até 8 caracteres"
            className="w-full border rounded px-3 py-2 mt-1"
          />
        </div>

        {/* Nome e Sobrenome */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Nome e Sobrenome
            <input
              className="w-full border rounded px-3 py-2 mt-1"
              required
              value={nome}
              onChange={handleNomeChange}
              placeholder="Nome e sobrenome"
              type="text"
            />
          </label>
        </div>

        {/* Novos campos opcionais em grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
          {[
            ['Nº Gaveta',      'numero_gaveta'],
            ['RG',             'rg'],
            ['CPF',            'cpf'],
            ['Data de Nascimento','data_nascimento'],
            ['Idade',          'idade'],
            ['Cidade',         'cidade'],
            ['Endereço',       'endereco'],
            ['Número',         'numero']
          ].map(([label, key]) => (
            <div key={key}>
              <label className="block mb-1 font-medium text-gray-700">{label}</label>
              <input
                type={key === 'data_nascimento' ? 'date' : (key==='idade'?'number':'text')}
                className="w-full border rounded px-3 py-2"
                value={formData[key]}
                onChange={e => setFormData({...formData, [key]: e.target.value})}
              />
            </div>
          ))}
          <div className="md:col-span-2">
            <label className="block mb-1 font-medium text-gray-700">Observação</label>
            <textarea
              className="w-full border rounded px-3 py-2"
              value={formData.observacao}
              onChange={e => setFormData({...formData, observacao: e.target.value})}
            />
          </div>
        </div>

        {/* Telefone */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Telefone
            <input
              className="w-full border rounded px-3 py-2 mt-1"
              required
              value={telefone}
              onChange={handleTelefoneChange}
              placeholder="(XX) XXXXX-XXXX"
              type="tel"
            />
          </label>
        </div>

        {/* Botões */}
        <div className="flex flex-col md:flex-row gap-4">
          <button
            type="submit"
            className="bg-[#1A1C2C] hover:bg-[#3B4854] text-white font-bold py-2 px-6 rounded-full"
          >
            {pacienteEditando ? 'Atualizar' : 'Cadastrar'}
          </button>
          {pacienteEditando && (
            <button
              type="button"
              className="bg-[#DA3648] hover:bg-[#BC3140] text-white px-4 py-2 rounded-full"
              onClick={onFimEdicao}
            >
              Cancelar
            </button>
          )}
        </div>

        {/* Feedback */}
        {mensagem && (
          <p className="mt-4 text-red-600">{mensagem}</p>
        )}
      </form>
    </div>
  );
}

export default FormPaciente;
